import React from 'react';

const entries = [
  {
    degree: 'Bachelor of Science in Information Technology',
    major: 'Major in Web Technology',
    school: 'Your University Name',
    year: '2023 – Present',
  },
  {
    degree: 'Senior High School',
    major: 'STEM / ICT Track',
    school: 'Your Senior High School',
    year: '2021 – 2023',
  },
];

const Education = () => (
  <section
    id="Education"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{
      background: '#071a33',
      fontFamily: "'Orbitron', sans-serif",
    }}
  >
    <h1 className="font-bold text-4xl text-white text-center mb-12">
      Education
    </h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          className="rounded-xl p-6 shadow-md"
          style={{
            background: '#0d2447',
            borderLeft: '5px solid #0d6efd',
          }}
        >
          <h3 className="font-bold text-lg text-white">{e.degree}</h3>

          <p className="italic text-sm mt-1" style={{ color: '#b8c7e6' }}>
            {e.major}
          </p>

          <p className="text-sm mt-2" style={{ color: '#9fb3d9' }}>
            {e.school}
          </p>

          <p className="text-xs mt-1" style={{ color: '#7f96c9' }}>
            {e.year}
          </p>
        </div>
      ))}
    </div>
  </section>
);

export default Education;
